const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type Step = { op: "quote"; items: Array<Item> };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<Step>;
};

const itemPremium = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  return base + base * FIRST_INSURANCE_RATE;
};

const quotePremium = (step: Step): number => {
  const sum = step.items.reduce((acc, item) => acc + itemPremium(item), 0);
  return sum + PROCESSING_FEE;
};

export const runScenario = (scenario: unknown): unknown => {
  const { steps } = scenario as Scenario;
  const results = steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};

